numbers = [1, 2, 2, 3, 3, 3, 4]

# set() removes duplicates automatically
unique = set(numbers)
print(unique)          # {1, 2, 3, 4}
print(len(unique))     # 4

# Set operations
even = {2, 4, 6, 8}
multiples_of_3 = {3, 6, 9}

print(even & multiples_of_3)   # intersection: {6}
print(even | multiples_of_3)   # union: all items
